VALUES
  ('social-worker-moex-06810', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作強調進行個案處遇（置）時，其干預（介入）必須有其理論（實務理論）依據。試問下列何者 是選取理論進行干預（介入）時不需要考慮的要點？', '["此一理論是否與個案的問題和其處遇（置）目標相符", "案主有無能力支付此理論依據進行處遇（置）的花費", "社工員有無足夠的知識和技能來運用此理論", "理論是否適合個人、家庭或團體的發展和週期"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06811', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作有時需要考慮改變團體的外在環境，請問考慮改變環境的理由包含下列那幾點？①成員的行為', '["環境對於團體與其中的成員產生標籤", "成員希望換環境或者新方式解決 問題", "成員要求工作者協助處理環境影響力  ⑤成員將自己的問題完全歸因環境因素", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06812', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列團體工作評鑑的測量方式或技術，何者是不適合評量團體過程改變的情形？', '["運用團體記錄內容的分析", "測量團體結構改變的工具", "記錄團體凝聚力改變過程", "團體成員重要他人的回應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06813', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那個組合是個別成員在團體中的功能性行為表現？  ①在團體中儘量避免被注意  ②願意對自己的', '["開放並正向的給予回饋", "懷柔安撫，以施恩者自居  ⑤談論前後無關聯性的話題 ⑥能與他人合作並給予支持", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06814', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者屬於團體工作者在團體結束時應完成的工作？①維持和普及化團體改變的成效  ②協助成員處', '["澄清團體與個人目標的關聯性", "與成員討論和釐清保密的範圍  ⑤降低團體吸 引力促進成員獨立", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06815', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '酗酒者匿名團體是屬於那一類型的團體工作方式？', '["自助團體", "教育性團體", "成長團體", "社區委員會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06816', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作非常強調專業關係的界線，尤其不得與案主有雙重的關係。但也有學者以為關係受文化脈絡影 響，要清楚判定關係界線並不容易。在考慮國情文化的脈絡之下，試問下列何者是清楚違反專業關係界 線情況的？', '["同時提供案主服務並發生性關係", "為鼓勵案主，送自己準備的獎品", "接受案主感謝協助所饋贈的土產", "與案主分享個人興趣來拉近關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06817', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '案主自我決定是社會工作非常重要的價值觀和倫理原則，但社工員在實務上往往遭遇操作此一倫理原則 的挑戰。事實上，案主自我決定並非無限上綱，而是有所限制。下列何者的陳述並非指陳可限制自我決 定的條件？', '["當案主所做的決定違反法律的規範", "案主有智慧做出對自己有利的決定", "案主不能做出積極且建設性的決定", "案主的決定與社會道德價值相衝突"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06818', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作非常強調保密的重要性。下列對於保密的陳述，何者正確？', '["即使案主向社工員透露自己會嚴重傷害他人的計畫或行為時，社工員仍然要保密", "若社工員取得案主的同意，社工員就可以向機構外合作的人員透露案主詳細的資料", "當案主生命與身體受到威脅時，例如性侵個案，社工員可有條件地透露保密訊息", "只要是機構裡的工作人員，包含辦事員，都可以共同分享案主的資訊而不算洩密"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06819', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對於社會工作業務過失的陳述，何者正確？', '["濫權是指社工員發生錯誤或不合法的行為", "瀆職是指社工員表現不適當卻未違法的行為", "業務過失是指社工員在工作上的無心之過", "怠職是指社工員遺漏或未完成應做之事"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "13ce809ec2ce", "answer_pdf_sha1": "99b28031b676", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
